'use strict';

var GetIntrinsic = require('get-intrinsic');

var $String = GetIntrinsic('%String%');
var $TypeError = require('es-errors/type');



module.exports = function NumberToString(x) {
	if (typeof x !== 'number') {
		throw new $TypeError('Assertion failed: `x` must be a Number');
	}

	return $String(x);
};
